import { test } from '@playwright/test';

test('debug with pause', async ({ page }) => {
  await page.goto('https://example.com');

  // Pause here - Inspector opens automatically
  await page.pause();

  // Continue with test after inspecting
  await page.click('button');

  // Pause again at a different point
  await page.pause();

  await page.fill('input', 'text');
});

// Pro tip: Remove page.pause() before committing!

// playwright.config.ts - Enable traces
export default defineConfig({
  use: {
    // Capture trace on first retry
    trace: 'on-first-retry',

    // Or always capture (slower)
    trace: 'on',

    // Or only on failure
    trace: 'retain-on-failure',
  },
});

